export default function VisaTemplate(name: string, passportNumber: string) {
    return `
    <html>
    <head>
        <style>
            body { font-family: Arial, sans-serif; margin: 40px; color: #333; }
            .header { text-align: center; color: #800080; font-size: 24px; font-weight: bold; }
            .content { margin-top: 20px; font-size: 18px; }
            .highlight { color: #993399; font-weight: bold; }
            .footer { margin-top: 30px; font-size: 16px; color: #555; text-align: center; }
        </style>
    </head>
    <body>
        <div class="header">Visa Confirmation Letter</div>
        <p class="content">Dear <span class="highlight">${name}</span>,</p>
        <p class="content">This letter confirms your eligibility for a student visa application. Your passport number is <span class="highlight">${passportNumber}</span>.</p>
        <p class="content">Please use this document while submitting your visa application.</p>
        <p class="footer">Best Regards,<br>Visa Office</p>
    </body>
    </html>
    `;
}
