export default function AdmissionLetterTemplate(name: string, program: string, university: string) {
    return `
    <html>
    <head>
        <style>
            body { font-family: Arial, sans-serif; margin: 40px; color: #333; }
            .header { text-align: center; color: #004080; font-size: 24px; font-weight: bold; }
            .content { margin-top: 20px; font-size: 18px; }
            .highlight { color: #0066cc; font-weight: bold; }
            .footer { margin-top: 30px; font-size: 16px; color: #555; text-align: center; }
        </style>
    </head>
    <body>
        <div class="header">Admission Letter</div>
        <p class="content">Dear <span class="highlight">${name}</span>,</p>
        <p class="content">Congratulations! You have been admitted to the <span class="highlight">${program}</span> program at <span class="highlight">${university}</span>. We are excited to welcome you to our institution.</p>
        <p class="content">Please ensure to complete all necessary formalities before the commencement of the program.</p>
        <p class="footer">Best Regards,<br>Admissions Office</p>
    </body>
    </html>
    `;
}
