export default function BonafideLetterTemplate(name: string, university: string) {
    return `
    <html>
    <head>
        <style>
            body { font-family: Arial, sans-serif; margin: 40px; color: #333; }
            .header { text-align: center; color: #007000; font-size: 24px; font-weight: bold; }
            .content { margin-top: 20px; font-size: 18px; }
            .highlight { color: #008000; font-weight: bold; }
            .footer { margin-top: 30px; font-size: 16px; color: #555; text-align: center; }
        </style>
    </head>
    <body>
        <div class="header">Bonafide Certificate</div>
        <p class="content">To Whom It May Concern,</p>
        <p class="content">This is to certify that <span class="highlight">${name}</span> is a bonafide student of <span class="highlight">${university}</span>. They are enrolled as a full-time student.</p>
        <p class="content">This certificate is issued upon request for official purposes.</p>
        <p class="footer">Best Regards,<br>University Administration</p>
    </body>
    </html>
    `;
}
