export default function PaymentReceiptTemplate(name: string, amount: number, transactionId: string) {
    return `
    <html>
    <head>
        <style>
            body { font-family: Arial, sans-serif; margin: 40px; color: #333; }
            .header { text-align: center; color: #002244; font-size: 24px; font-weight: bold; }
            .content { margin-top: 20px; font-size: 18px; }
            .highlight { color: #004466; font-weight: bold; }
            .footer { margin-top: 30px; font-size: 16px; color: #555; text-align: center; }
        </style>
    </head>
    <body>
        <div class="header">Payment Receipt</div>
        <p class="content">Dear <span class="highlight">${name}</span>,</p>
        <p class="content">Thank you for your payment of <span class="highlight">$${amount}</span>. Your transaction ID is <span class="highlight">${transactionId}</span>.</p>
        <p class="content">This receipt serves as official proof of your payment.</p>
        <p class="footer">Best Regards,<br>Finance Department</p>
    </body>
    </html>
    `;
}
